import{_ as s,o as a,c as e,d as n}from"./app.22d6dd61.js";const A=JSON.parse('{"title":"Rust Guide","description":"","frontmatter":{},"headers":[{"level":2,"title":"1. Iroha 2 Client Setup","slug":"_1-iroha-2-client-setup"},{"level":2,"title":"2. Configuring Iroha 2","slug":"_2-configuring-iroha-2"},{"level":2,"title":"3. Registering a Domain","slug":"_3-registering-a-domain"},{"level":2,"title":"4. Registering an Account","slug":"_4-registering-an-account"},{"level":2,"title":"5. Registering and minting assets","slug":"_5-registering-and-minting-assets"},{"level":2,"title":"6. Visualising outputs","slug":"_6-visualising-outputs"}],"relativePath":"guide/rust.md","lastUpdated":1659428266000}'),o={name:"guide/rust.md"},t=n(`<h1 id="rust-guide" tabindex="-1">Rust Guide <a class="header-anchor" href="#rust-guide" aria-hidden="true">#</a></h1><h2 id="_1-iroha-2-client-setup" tabindex="-1">1. Iroha 2 Client Setup <a class="header-anchor" href="#_1-iroha-2-client-setup" aria-hidden="true">#</a></h2><p>In this part we shall cover the process of using the Iroha 2 Rust libraries. Instead of providing the complete basics, we shall assume knowledge of the most widely used concepts, explain what&#39;s unusual about Iroha 2 specifically, and provide a step-by-step guide to creating your own Rust client for it.</p><p>We assume that you know how to create a new package and have basic understanding of the fundamental Rust code; <code>async</code> functions, <code>enum</code> types, traits and borrowing/ownership, as well as the libraries that we use: <code>serde</code>, <code>tokio</code>, <code>tracing</code>, etc.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If you don&#39;t feel comfortable with any of the above, we recommend consulting <a href="https://doc.rust-lang.org/stable/book/" target="_blank" rel="noopener noreferrer">the Rust book</a> and <a href="https://docs.rs/" target="_blank" rel="noopener noreferrer">docs.rs</a>.</p></div><p>Iroha 2 makes extensive use of <a href="https://doc.rust-lang.org/book/ch14-03-cargo-workspaces.html" target="_blank" rel="noopener noreferrer">workspaces</a>. Currently, there are two workspaces, the one that contains the WASM support library and the one that contains the core support libraries, which go in a domain-first order. What that means is that instead of having a global <em>constants</em> crate, we have a crate for the blockchain data model (<code>iroha_data_model</code>), a crate with cryptographic primitives (<code>iroha_crypto</code>), and so on. These, <em>individually</em>, have a module for constants.</p><p>If you add <code>iroha_client</code> to the other two crates, you get the minimum number of dependencies to start your own client, similar to <code>iroha_client_cli</code>.</p><p>Once the initial <code>v2.0.0</code> release is complete, we plan to create a package on <a href="https://crates.io/" target="_blank" rel="noopener noreferrer">crates.io</a> with all the documentation. In the meantime, you could use the local copy that you&#39;ve just created in the <a href="/iroha-2-docs/guide/build-and-install.html">previous step</a> as a local installation in your client&#39;s <code>Cargo.toml</code>:</p><div class="language-toml"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#ADBAC7;">[</span><span style="color:#F69D50;">dependencies</span><span style="color:#ADBAC7;">]</span></span>
<span class="line"><span style="color:#ADBAC7;">iroha_client = { version = </span><span style="color:#96D0FF;">&quot;=2.0.0-pre-rc.4&quot;</span><span style="color:#ADBAC7;">, path = </span><span style="color:#96D0FF;">&quot;~/Git/iroha/client&quot;</span><span style="color:#ADBAC7;"> }</span></span>
<span class="line"><span style="color:#ADBAC7;">iroha_data_model = { version = </span><span style="color:#96D0FF;">&quot;=2.0.0-pre-rc.4&quot;</span><span style="color:#ADBAC7;">, path = </span><span style="color:#96D0FF;">&quot;~/Git/iroha/data_model&quot;</span><span style="color:#ADBAC7;"> }</span></span>
<span class="line"><span style="color:#ADBAC7;">iroha_crypto = { version = </span><span style="color:#96D0FF;">&quot;=2.0.0-pre-rc.4&quot;</span><span style="color:#ADBAC7;">, path = </span><span style="color:#96D0FF;">&quot;~/Git/iroha/crypto&quot;</span><span style="color:#ADBAC7;"> }</span></span>
<span class="line"></span></code></pre></div><p>The added benefit of using a local copy is that you have access to the minimal BFT network in the form of <code>docker-compose.yml</code>, which allows you to experiment. The drawbacks are mitigated by the fact that Rust links statically by default, so we recommend you experiment with the local set up first.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>You could also make use of our <code>test_network</code> crate, which is available via <a href="https://github.com/hyperledger/iroha/tree/iroha2/core/test_network" target="_blank" rel="noopener noreferrer">GitHub</a> but not via <a href="http://crates.io" target="_blank" rel="noopener noreferrer">crates.io</a>.</p></div><p>You would also benefit from having immediate access to the example configurations in the <code>~/Git/iroha/configs</code> folder.</p><p>So let&#39;s copy the example client configuration somewhere useful:</p><div class="language-bash"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#ADBAC7;">cp -vfr </span><span style="color:#F47067;">~</span><span style="color:#ADBAC7;">/Git/iroha/configs/client_cli/config.json example/config.json</span></span>
<span class="line"></span></code></pre></div><p>We recommend looking through it to familiarise yourself with the key pieces of information that every Iroha 2 client needs. Specifically, each client operates on behalf of a pre-existing account. These accounts are identified by a <em>name@domain_name</em> ID and can only be accessed provided that you know their specific key.</p><h2 id="_2-configuring-iroha-2" tabindex="-1">2. Configuring Iroha 2 <a class="header-anchor" href="#_2-configuring-iroha-2" aria-hidden="true">#</a></h2><p>Your application written in Rust needs to instantiate a client. The client typically needs specific configuration options, which you could either generate or load from the provided <code>config.json</code>. Let&#39;s do that now:</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#F47067;">use</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">iroha_client</span><span style="color:#F47067;">::</span><span style="color:#F69D50;">config</span><span style="color:#F47067;">::</span><span style="color:#F69D50;">Configuration</span><span style="color:#ADBAC7;"> </span><span style="color:#F47067;">as</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">ClientConfiguration</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> cfg</span><span style="color:#F47067;">:</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">ClientConfiguration</span><span style="color:#ADBAC7;"> </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">serde_json</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">from_reader</span><span style="color:#ADBAC7;">(file)</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span></code></pre></div><p>Using said configuration, instantiate a client:</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#F47067;">use</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">iroha_client</span><span style="color:#F47067;">::</span><span style="color:#F69D50;">client</span><span style="color:#F47067;">::</span><span style="color:#F69D50;">Client</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> iroha_client </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">Client</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">new</span><span style="color:#ADBAC7;">(cfg)</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span></code></pre></div><p>Note that it used to be necessary to create a mutable client. Sending and receiving messages affects the client&#39;s internal state, but now that state is hidden behind interior mutable smart pointers.</p><p>Of course, depending on your application, you might want to de-serialise your <code>ClientConfiguration</code> structure from a different location. Perhaps, you might want to build the configuration in place using the command-line arguments, or perhaps, you&#39;re using the XDG specification to store the file persistently in a different location. For this purpose, it&#39;s useful to try and construct the <code>ClientConfiguration</code>:</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#F47067;">use</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">iroha_core</span><span style="color:#F47067;">::</span><span style="color:#F69D50;">prelude</span><span style="color:#F47067;">::*</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"><span style="color:#F47067;">use</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">iroha_data_model</span><span style="color:#F47067;">::</span><span style="color:#F69D50;">prelude</span><span style="color:#F47067;">::*</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> kp </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">KeyPair</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">new</span><span style="color:#ADBAC7;">(</span></span>
<span class="line"><span style="color:#ADBAC7;">    </span><span style="color:#F69D50;">PublicKey</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">from_str</span><span style="color:#ADBAC7;">(</span></span>
<span class="line"><span style="color:#ADBAC7;">        </span><span style="color:#96D0FF;">r#&quot;ed01207233bfc89dcbd68c19fde6ce6158225298ec1131b6a130d1aeb454c1ab5183c0&quot;#</span><span style="color:#ADBAC7;">,</span></span>
<span class="line"><span style="color:#ADBAC7;">    )</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">,</span></span>
<span class="line"><span style="color:#ADBAC7;">    </span><span style="color:#F69D50;">PrivateKey</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">from_hex</span><span style="color:#ADBAC7;">(</span></span>
<span class="line"><span style="color:#ADBAC7;">        </span><span style="color:#F69D50;">Algorithm</span><span style="color:#F47067;">::</span><span style="color:#6CB6FF;">ED25519</span><span style="color:#ADBAC7;">,</span></span>
<span class="line"><span style="color:#ADBAC7;">        </span><span style="color:#96D0FF;">&quot;9ac47abf59b356e0bd7dcbbbb4dec080e302156a48ca907e47cb6aea1d32719e7233bfc89dcbd68c19fde6ce6158225298ec1131b6a130d1aeb454c1ab5183c0&quot;</span><span style="color:#ADBAC7;">)</span></span>
<span class="line"><span style="color:#ADBAC7;">        </span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">into</span><span style="color:#ADBAC7;">(),</span></span>
<span class="line"><span style="color:#ADBAC7;">    ),</span></span>
<span class="line"><span style="color:#ADBAC7;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> (public_key, private_key) </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> kp</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">clone</span><span style="color:#ADBAC7;">()</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">into</span><span style="color:#ADBAC7;">();</span></span>
<span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> account_id</span><span style="color:#F47067;">:</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">AccountId</span><span style="color:#ADBAC7;"> </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#96D0FF;">&quot;alice@wonderland&quot;</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">parse</span><span style="color:#ADBAC7;">()</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> cfg </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">ClientConfiguration</span><span style="color:#ADBAC7;"> {</span></span>
<span class="line"><span style="color:#ADBAC7;">    public_key,</span></span>
<span class="line"><span style="color:#ADBAC7;">    private_key,</span></span>
<span class="line"><span style="color:#ADBAC7;">    account_id,</span></span>
<span class="line"><span style="color:#ADBAC7;">    torii_api_url</span><span style="color:#F47067;">:</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">iroha_data_model</span><span style="color:#F47067;">::</span><span style="color:#F69D50;">uri</span><span style="color:#F47067;">::</span><span style="color:#6CB6FF;">DEFAULT_API_URL</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">to_owned</span><span style="color:#ADBAC7;">(),</span></span>
<span class="line"><span style="color:#ADBAC7;">    </span><span style="color:#F47067;">..</span><span style="color:#F69D50;">ClientConfiguration</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">default</span><span style="color:#ADBAC7;">()</span></span>
<span class="line"><span style="color:#ADBAC7;">};</span></span>
<span class="line"></span></code></pre></div><p>There are a few things that may prove confusing.</p><p>If you look at the <code>config.json</code>, you&#39;ll see that the keys are given in <a href="https://github.com/multiformats/multihash" target="_blank" rel="noopener noreferrer">multi-hash format</a>. If you&#39;ve never worked with multi-hash before, it is natural to assume that the right-hand-side is not a hexadecimal representation of the key bytes (two symbols per byte), but rather the bytes encoded as ASCII (or UTF-8), and call <code>from_hex</code> on the string literal in both the <code>public_key</code> and <code>private_key</code> instantiation.</p><p>It is also natural to assume that calling <code>PrivateKey::try_from_str</code> on the string literal would yield only the correct key. So if you get the number of bits in the key wrong, e.g. 32 bytes vs 64, that it would raise an error message.</p><p><strong>Both of these assumptions are wrong.</strong> Unfortunately, the error messages don&#39;t help in de-bugging this particular kind of failure.</p><p><strong>How to fix</strong>: use <code>hex_literal</code>. This will also turn an ugly string of characters into a nice small table of obviously hexadecimal numbers.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Even the <code>try_from_str</code> implementation cannot verify if a given string is a valid <code>PrivateKey</code> and warn you if it isn&#39;t.</p><p>It will catch some obvious errors, e.g. if the string contains an invalid symbol. However, since we aim to support many key formats, it can&#39;t do much else. It cannot tell if the key is the <em>correct</em> private key <em>for the given account</em> either, unless you submit an instruction.</p></div><p>These sorts of subtle mistakes can be avoided, for example, by deserialising directly from string literals, or by generating a fresh key-pair in places where it makes sense.</p><h2 id="_3-registering-a-domain" tabindex="-1">3. Registering a Domain <a class="header-anchor" href="#_3-registering-a-domain" aria-hidden="true">#</a></h2><p>Registering a domain is a relatively easy operation. Most of the boilerplate code has to do with setting up the Iroha 2 client and deserialising its configuration. To register a domain, you need the domain name;</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#F47067;">use</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">iroha_data_model</span><span style="color:#F47067;">::</span><span style="color:#F69D50;">prelude</span><span style="color:#F47067;">::*</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> looking_glass</span><span style="color:#F47067;">:</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">DomainId</span><span style="color:#ADBAC7;"> </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#96D0FF;">&quot;looking_glass&quot;</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">parse</span><span style="color:#ADBAC7;">()</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span></code></pre></div><p>Which we convert into an instruction:</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"></span>
<span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> create_looking_glass </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">RegisterBox</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">new</span><span style="color:#ADBAC7;">(</span><span style="color:#F69D50;">Domain</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">new</span><span style="color:#ADBAC7;">(looking_glass</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">clone</span><span style="color:#ADBAC7;">()));</span></span>
<span class="line"></span></code></pre></div><p>Note that we use <code>RegisterBox</code> and <code>IdentifiableBox</code>. Despite what your instincts as a Rust developer might suggest, we&#39;re not actually using any kind of dynamic dispatch. There&#39;s no <code>dyn</code> anywhere, and <code>RegisterBox</code> isn&#39;t an alias for <code>Box&lt;dyn Register&gt;</code>.</p><p>A <code>RegisterBox</code> is a specialised <code>enum</code> that uses static dispatch to achieve what looks like dynamic dispatch, without any heap allocation. If you want to add more types to <code>RegisterBox</code> you must either open an issue on GitHub, or do that by yourself on a local fork of Iroha.</p><p>The instruction is then batched into a transaction:</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> tx </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> iroha_client</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">build_transaction</span><span style="color:#ADBAC7;">([create_looking_glass], </span><span style="color:#F69D50;">Metadata</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">default</span><span style="color:#ADBAC7;">())</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span></code></pre></div><p>Which is then submitted into the pipeline:</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#ADBAC7;">iroha_client</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">submit_transaction</span><span style="color:#ADBAC7;">(tx)</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span></code></pre></div><p>Note the question mark here. This will return an <code>Err</code> variant if there&#39;s something immediately and obviously wrong with the transaction: for example, if it couldn&#39;t submit the transaction to the peer (e.g. there&#39;s no connection), or if the transaction got rejected with an error. The cost is that the <code>submit_transaction</code> function is synchronous.</p><p>We could have also done the following:</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#ADBAC7;">iroha_client</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">submit_with_metadata</span><span style="color:#ADBAC7;">(create_looking_glass, </span><span style="color:#F69D50;">Metadata</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">default</span><span style="color:#ADBAC7;">())</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span></code></pre></div><p>or</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#ADBAC7;">iroha_client</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">submit</span><span style="color:#ADBAC7;">(create_looking_glass)</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span></code></pre></div><p>The latter style is just syntactic sugar. Every submission comes in the form of a transaction that has metadata.</p><p>While the latter is a convenient shorthand that we shall use frequently, we strongly advise using explicit construction in production code.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>It is likely that we shall replace most if not all instances of <code>submit</code> in our code base with explicit transactions.</p></div><h2 id="_4-registering-an-account" tabindex="-1">4. Registering an Account <a class="header-anchor" href="#_4-registering-an-account" aria-hidden="true">#</a></h2><p>Registering an account is a bit more involved than registering a domain. With a domain, the only concern is the domain name. However, with an account, there are a few more things to worry about.</p><p>First of all, we need to create an <code>AccountId</code>. Note that we can only register an account to an existing domain. The best UX design practices dictate that you should check if the requested domain exists <em>now</em>, and if it doesn&#39;t, suggest a fix to the user. After that, we can create a new account named <em>white_rabbit</em>.</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> longhand_id </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">iroha_data_model</span><span style="color:#F47067;">::</span><span style="color:#F69D50;">account</span><span style="color:#F47067;">::</span><span style="color:#F69D50;">Id</span><span style="color:#ADBAC7;"> {</span></span>
<span class="line"><span style="color:#ADBAC7;">    name</span><span style="color:#F47067;">:</span><span style="color:#ADBAC7;"> </span><span style="color:#96D0FF;">&quot;white_rabbit&quot;</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">parse</span><span style="color:#ADBAC7;">()</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">,</span></span>
<span class="line"><span style="color:#ADBAC7;">    domain_name</span><span style="color:#F47067;">:</span><span style="color:#ADBAC7;"> </span><span style="color:#96D0FF;">&quot;looking_glass&quot;</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">parse</span><span style="color:#ADBAC7;">()</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">,</span></span>
<span class="line"><span style="color:#ADBAC7;">};</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> account_id</span><span style="color:#F47067;">:</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">AccountId</span><span style="color:#ADBAC7;"> </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#96D0FF;">&quot;white_rabbit@looking_glass&quot;</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">parse</span><span style="color:#ADBAC7;">();</span></span>
<span class="line"><span style="color:#DCBDFB;">assert_eq!</span><span style="color:#ADBAC7;">(longhand_id, id);</span></span>
<span class="line"></span></code></pre></div><p>Second, you should provide the account with a public key. It is tempting to generate both it and the private key at this time, but it isn&#39;t the brightest idea. Remember, that <em>the white_rabbit</em> trusts <em>you, alice@wonderland</em>, to create an account for them in the domain _looking_glass, <strong>but doesn&#39;t want you to have access to that account after creation</strong>.</p><p>If you gave <em>white_rabbit</em> a key that you generated yourself, how would they know if you don&#39;t have a copy of their private key? Instead, the best way is to <strong>ask</strong> <em>white_rabbit</em> to generate a new key-pair, and give you the public half of it:</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> key</span><span style="color:#F47067;">:</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">PublicKey</span><span style="color:#ADBAC7;"> </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#DCBDFB;">get_key_from_white_rabbit</span><span style="color:#ADBAC7;">();</span></span>
<span class="line"></span></code></pre></div><p>Only then do we build an instruction from it:</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> create_account </span><span style="color:#F47067;">=</span></span>
<span class="line"><span style="color:#ADBAC7;">    </span><span style="color:#F69D50;">RegisterBox</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">new</span><span style="color:#ADBAC7;">(</span><span style="color:#F69D50;">IdentifiableBox</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">from</span><span style="color:#ADBAC7;">(</span><span style="color:#F69D50;">NewAccount</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">with_signatory</span><span style="color:#ADBAC7;">(id, key)));</span></span>
<span class="line"></span></code></pre></div><p>Which is then <strong>wrapped in a transaction</strong> and <strong>submitted to the peer</strong> as <a href="#_3-registering-a-domain">in the previous section</a>.</p><h2 id="_5-registering-and-minting-assets" tabindex="-1">5. Registering and minting assets <a class="header-anchor" href="#_5-registering-and-minting-assets" aria-hidden="true">#</a></h2><p>Iroha has been built with few underlying assumptions about what the assets need to be.</p><p>The assets can be fungible (every \xA31 is exactly the same as every other \xA31), or non-fungible (a \xA31 bill signed by the Queen of Hearts is not the same as a \xA31 bill signed by the King of Spades), mintable (you can make more of them) and non-mintable (you can only specify their initial quantity in the genesis block).</p><p>Additionally, the assets have different underlying value types. Specifically, we have <code>AssetValueType.Quantity</code>, which is effectively an unsigned 32-bit integer, a <code>BigQuantity</code>, which is an unsigned 128-bit integer, and <code>Fixed</code>, which is a positive (though signed) 64-bit fixed-precision number with nine significant digits after the decimal point. All three types can be registered as either <strong>mintable</strong> or <strong>non-mintable</strong>.</p><p>Now, let&#39;s get back to coding. To register an asset, we first construct an <code>iroha_data_model::asset::DefinitionId</code> like so:</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> id </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">AssetDefinitionId</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">from_str</span><span style="color:#ADBAC7;">(</span><span style="color:#96D0FF;">&quot;time#looking_glass&quot;</span><span style="color:#ADBAC7;">)</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Note that we use <code>#</code> symbol to separate the name of the asset from the domain to which it belongs. This is intentional. This reflects the rule that there can be many <code>alice</code>s in many domains, with only one <code>alice</code> per domain, and there can be an asset that is also named <code>alice</code>, but there can be only one, regardless of type.</p></div><p>Then construct an instruction:</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> register_time </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">RegisterBox</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">new</span><span style="color:#ADBAC7;">(</span><span style="color:#F69D50;">AssetDefinition</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">fixed</span><span style="color:#ADBAC7;">(id)</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">mintable_once</span><span style="color:#ADBAC7;">());</span></span>
<span class="line"><span style="color:#ADBAC7;">iroha_client</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">submit</span><span style="color:#ADBAC7;">(register_time)</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span></code></pre></div><p>This creates an asset <code>time</code> that can only be minted once and has the type <code>fixed</code>. <code>AssetDefinition::fixed</code> just like its other cousins (<code>quantity</code> and <code>big_quantity</code>) returns a builder of an <code>AssetDefinition</code>.</p><p>This asset is <code>mintable_once</code>, which means that the next time we mint it, we have to specify the entire amount that is going to exist for the rest of the existence of the blockchain.</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> mint </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">MintBox</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">new</span><span style="color:#ADBAC7;">(</span></span>
<span class="line"><span style="color:#ADBAC7;">    </span><span style="color:#F69D50;">Value</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">Fixed</span><span style="color:#ADBAC7;">(</span><span style="color:#6CB6FF;">12.34_</span><span style="color:#F69D50;">f64</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">try_into</span><span style="color:#ADBAC7;">()</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">),</span></span>
<span class="line"><span style="color:#ADBAC7;">    </span><span style="color:#F69D50;">IdBox</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">AssetId</span><span style="color:#ADBAC7;">(</span><span style="color:#F69D50;">AssetId</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">new</span><span style="color:#ADBAC7;">(</span></span>
<span class="line"><span style="color:#ADBAC7;">        id</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">clone</span><span style="color:#ADBAC7;">(),</span></span>
<span class="line"><span style="color:#ADBAC7;">        account_id</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">clone</span><span style="color:#ADBAC7;">()</span></span>
<span class="line"><span style="color:#ADBAC7;">    ))</span></span>
<span class="line"><span style="color:#ADBAC7;">);</span></span>
<span class="line"><span style="color:#ADBAC7;">iroha_client</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">submit</span><span style="color:#ADBAC7;">(mint)</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span></code></pre></div><p>Now imagine that the <code>white_rabbit@looking_glass</code> was not very keen and didn&#39;t notice that he wanted <code>123.4_f64</code> as the amount of time. Now white rabbit notices the problem and thinks &quot;oh dear, not a lot of time has passed, perhaps I can give myself some more&quot;, and submits another mint request with <code>111.06_f64</code> instead of the original <code>12.34_f64</code>. But, alas, no such luck. The white rabbit cannot mint more time and is thus perpetually late.</p><p>Roses, by contrast, are already registered in the network during the genesis round, and belong to <em>alice@wonderland</em>. Moreover, when they were registered, we didn&#39;t add the restriction, so we can mint them again and again as <em>alice</em>:</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> mint_roses </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">MintBox</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">new</span><span style="color:#ADBAC7;">(</span></span>
<span class="line"><span style="color:#ADBAC7;">    </span><span style="color:#F69D50;">Value</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">U32</span><span style="color:#ADBAC7;">(</span><span style="color:#6CB6FF;">42</span><span style="color:#ADBAC7;">),</span></span>
<span class="line"><span style="color:#ADBAC7;">    </span><span style="color:#F69D50;">IdBox</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">AssetId</span><span style="color:#ADBAC7;">(</span><span style="color:#F69D50;">AssetId</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">new</span><span style="color:#ADBAC7;">(roses</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">clone</span><span style="color:#ADBAC7;">(), alice</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">clone</span><span style="color:#ADBAC7;">())),</span></span>
<span class="line"><span style="color:#ADBAC7;">);</span></span>
<span class="line"></span></code></pre></div><p>Which we then submit as usual.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Our assets are strongly typed. As such, when you create a <code>MintBox</code>, you need to check that the asset has the correct underlying type. If you don&#39;t know the type, query it. This is also why we specifically annotate numerical literals with their type.</p><p>Contrary to what you might think, this restriction isn&#39;t just for pedantry. Implicit conversion errors are the bane of all programmers, if you got the <em>AssetValueType</em> incorrect, <em>how do you know that it was the only mistake in that transaction?</em></p></div><h2 id="_6-visualising-outputs" tabindex="-1">6. Visualising outputs <a class="header-anchor" href="#_6-visualising-outputs" aria-hidden="true">#</a></h2><p>Finally, we should talk about visualising data. The Rust API is currently the most complete in terms of available queries and instructions. After all, this is the language in which Iroha 2 was built.</p><p>We shall, however, leave most of the aforementioned advanced features down the rabbit hole, up to the reader&#39;s own devices to discover. This document can easily get out of sync with the state of the API features. By contrast, the online documentation is always up to date. Plus a short tutorial wouldn&#39;t be able to do all these features justice. Instead, we shall retain parity with other language tutorials and introduce you to pipeline filters.</p><p>There are two possible event filters: <code>PipelineEventFilter</code> and <code>DataEventFilter</code>, we shall focus on the former. This filter sieves events pertaining to the process of submitting a transaction, executing a transaction, and committing it to a block.</p><p>First, let&#39;s build a filter:</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#F47067;">use</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">iroha_data_model</span><span style="color:#F47067;">::</span><span style="color:#F69D50;">prelude</span><span style="color:#F47067;">::*</span><span style="color:#ADBAC7;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F47067;">let</span><span style="color:#ADBAC7;"> filter </span><span style="color:#F47067;">=</span><span style="color:#ADBAC7;"> </span><span style="color:#F69D50;">FilterBox</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">Pipeline</span><span style="color:#ADBAC7;">(</span><span style="color:#F69D50;">PipelineEventFilter</span><span style="color:#F47067;">::</span><span style="color:#DCBDFB;">identity</span><span style="color:#ADBAC7;">());</span></span>
<span class="line"></span></code></pre></div><p>Then, we start listening for events in an infinite loop:</p><div class="language-rust"><span class="copy"></span><pre class="shiki" style="background-color:#22272e;"><code><span class="line"><span style="color:#F47067;">for</span><span style="color:#ADBAC7;"> event </span><span style="color:#F47067;">in</span><span style="color:#ADBAC7;"> iroha_client</span><span style="color:#F47067;">.</span><span style="color:#DCBDFB;">listen_for_events</span><span style="color:#ADBAC7;">(filter)</span><span style="color:#F47067;">?</span><span style="color:#ADBAC7;"> {</span></span>
<span class="line"><span style="color:#ADBAC7;">    </span><span style="color:#F47067;">match</span><span style="color:#ADBAC7;"> event {</span></span>
<span class="line"><span style="color:#ADBAC7;">        </span><span style="color:#F69D50;">Ok</span><span style="color:#ADBAC7;">(event) </span><span style="color:#F47067;">=&gt;</span><span style="color:#ADBAC7;"> </span><span style="color:#DCBDFB;">println!</span><span style="color:#ADBAC7;">(</span><span style="color:#96D0FF;">&quot;Success: {:#?}&quot;</span><span style="color:#ADBAC7;">, event),</span></span>
<span class="line"><span style="color:#ADBAC7;">        </span><span style="color:#F69D50;">Err</span><span style="color:#ADBAC7;">(err) </span><span style="color:#F47067;">=&gt;</span><span style="color:#ADBAC7;"> </span><span style="color:#DCBDFB;">println!</span><span style="color:#ADBAC7;">(</span><span style="color:#96D0FF;">&quot;Sadness:( {:#?}&quot;</span><span style="color:#ADBAC7;">,  err),</span></span>
<span class="line"><span style="color:#ADBAC7;">    }</span></span>
<span class="line"><span style="color:#ADBAC7;">};</span></span>
<span class="line"></span></code></pre></div><p>Needless to say, an synchronous infinite blocking loop is bad UX for anything but a command-line program, but for illustration purposes, this would create a nice printout, just like in <code>iroha_client_cli</code>.</p>`,85),l=[t];function p(c,r,i,y,d,h){return a(),e("div",null,l)}var D=s(o,[["render",p]]);export{A as __pageData,D as default};
